import React from 'react';
import { SmallChopsMenu } from './data';

const SmallChops = () => {
  return (
    <section style={{ backgroundColor: '#0A0A0A', color: '#FFF', padding: '50px 20px' }}>
      <h2 style={{ textAlign: 'center', color: '#D4AF37', textTransform: 'uppercase', letterSpacing: '2px' }}>Small Chops Collections</h2>
      <p style={{ textAlign: 'center', color: '#E07A5F', marginBottom: '40px' }}>Taste and Style in Every Bite</p>
      
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '25px', maxWidth: '1200px', margin: '0 auto' }}>
        {smallChopsMenu.map((pack) => (
          <div key={pack.id} style={{ border: '1px solid #222', borderRadius: '10px', background: '#111', padding: '20px' }}>
            <h3 style={{ borderBottom: '2px solid #E07A5F', paddingBottom: '10px', marginBottom: '15px' }}>{pack.name}</h3>
            
            <div style={{ marginBottom: '20px' }}>
              {pack.contents.map((line, i) => (
                <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: '1px solid #222' }}>
                  <span style={{ color: '#AAA' }}>{line.icon} {line.item}</span>
                  <span style={{ color: '#D4AF37', fontWeight: 'bold' }}>{line.qty}</span>
                </div>
              ))}
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '20px' }}>
              <span style={{ fontSize: '1.3rem', fontWeight: 'bold' }}>₦{pack.price}</span>
              <button style={{ background: '#D4AF37', color: '#000', border: 'none', padding: '10px 20px', borderRadius: '5px', fontWeight: '700', cursor: 'pointer' }}>Order Now</button>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default SmallChops;
